// Lee el texto devuelto por el Message a model
const raw = $('Message a model').first().json.message.content;
// --- Limpieza robusta del string ---
let s = String(raw).trim();
// 1) Si viene dentro de ```json ... ``` o ``` ... ``` quítalo
s = s
  .replace(/^```(?:json)?\s*/i, '')   // abre fence
  .replace(/```$/i, '')               // cierra fence
  .trim();
// 2) Si por cualquier motivo hay texto extra, quédate con lo que haya entre el
//    primer '{' y el último '}'
const firstBrace = s.indexOf('{');
const lastBrace  = s.lastIndexOf('}');
if (firstBrace !== -1 && lastBrace !== -1) {
  s = s.slice(firstBrace, lastBrace + 1).trim();
}
// 3) Quitar posibles comas colgantes (por si el modelo las puso)
s = s.replace(/,\s*([}\]])/g, '$1');
let obj;
try {
  obj = JSON.parse(s);
} catch (e) {
  throw new Error('No se pudo parsear el JSON del modelo. Recibido:\n' + s);
}

// --- Cálculo de IVA y total ---
const precio = parseFloat(obj.precio) || 0;
const iva    = Math.round(precio * 0.21 * 100) / 100;
const total  = Math.round((precio + iva)  * 100) / 100;

// Devuelve cada campo como parámetros separados
return [
  {
    empresa:     obj.empresa     ?? '',
    fecha:       obj.fecha       ?? '',
    factura:     obj.factura     ?? '',
    servicio:    obj.servicio    ?? '',
    descripcion: obj.descripcion ?? '',
    precio:      obj.precio      ?? '',
    iva:         iva.toFixed(2),    // → "735.00"
    total:       total.toFixed(2),  // → "4235.00"
  }
];

